cd /tmp/sv-c5c537df1b4147919b025834c9da6e00
# Get full symbol names - the readelf output may be truncating
readelf --dyn-syms --wide libmonosgen-2.0.so.dbg 2>/dev/null | awk '$4 == "FUNC" && $2 != "0000000000000000" {print $2, $3, $8}' | sort > dynsyms_full.txt

python3 -c "
import sys

# Load symbols with sizes
symbols = []
with open('dynsyms_full.txt') as f:
    for line in f:
        parts = line.strip().split(None, 2)
        if len(parts) == 3:
            addr = int(parts[0], 16)
            size = int(parts[1])
            name = parts[2]
            symbols.append((addr, size, name))

symbols.sort()

def lookup(pc):
    best = None
    for addr, size, name in symbols:
        if addr <= pc:
            best = (addr, size, name)
        else:
            break
    if best and (pc < best[0] + best[1] or best[1] == 0):
        return best
    return best  # best guess even if outside reported size

addresses = {
    'Thread 7020 (main/crash)': [
        (0x222098, '#01'),
        (0x2241ac, '#02'),
        (0x1abc80, '#03'),
        (0x16de04, '#04'),
    ],
    'Thread 7046 (SGen worker)': [
        (0x2f4b20, '#02'),
        (0x2f4c84, '#03'),
    ],
    'Thread 7048 (Finalizer)': [
        (0x2c1a40, '#02'),
    ],
}

for thread, addrs in addresses.items():
    print(f'\n{thread}:')
    for pc, frame in addrs:
        result = lookup(pc)
        if result:
            offset = pc - result[0]
            print(f'  {frame} pc 0x{pc:08x} -> {result[2]}+0x{offset:x}')
        else:
            print(f'  {frame} pc 0x{pc:08x} -> ???')
"

