cd /tmp/sv-c5c537df1b4147919b025834c9da6e00
# Check ALL symbols (not just FUNC) near those addresses
aarch64-linux-gnu-nm --defined-only libmonosgen-2.0.so.debug 2>/dev/null | sort | awk -v pc1="2f4b20" -v pc2="2f4c84" '
{
  addr = $1
  if (addr <= pc1) { best1_addr = addr; best1_name = $3 }
  if (addr <= pc2) { best2_addr = addr; best2_name = $3 }
}
END {
  print "0x" pc1 " -> " best1_name " (at 0x" best1_addr ")"
  print "0x" pc2 " -> " best2_name " (at 0x" best2_addr ")"
}'
echo "---"
# Try llvm-symbolizer with different options - use -f to force function lookup
llvm-symbolizer --obj=libmonosgen-2.0.so.debug --output-style=LLVM --verbose 0x2f4b20 0x2f4c84 2>/dev/null
echo "---"
# Also look for OBJECT symbols that might be sgen-related near those addresses
aarch64-linux-gnu-nm --defined-only libmonosgen-2.0.so.debug 2>/dev/null | sort | grep -i sgen | grep -E "^00000000002[ef]" | head -20

